import { PublicCard } from '../../../types';

export const technologyCards: PublicCard[] = [
  { id: 'dc-technology-0001', deck_id: 'deck-technology', sort_order: 1, front: "Array", back: "A data structure storing elements of the same type in contiguous memory locations. Supports O(1) random access by index but O(n) insertion/deletion in the middle. Most fundamental data structure." , front_translations: {"de":"Array","fr":"Tableau (Array)","tr":"Dizi (Array)","nl":"Array","ru":"Массив","zh":"数组","pt_BR":"Array","pt_PT":"Array"}, back_translations: {"de":"Eine Datenstruktur, die Elemente des gleichen Typs an zusammenhängenden Speicheradressen speichert. Unterstützt O(1) Direktzugriff per Index, aber O(n) beim Einfügen/Löschen in der Mitte. Die grundlegendste Datenstruktur.","fr":"Une structure de données stockant des éléments du même type dans des emplacements mémoire contigus. Accès aléatoire en O(1) par index, mais insertion/suppression au milieu en O(n). Structure de données la plus fondamentale.","tr":"Aynı türdeki elemanları ardışık bellek konumlarında depolayan bir veri yapısı. İndeks ile O(1) rastgele erişimi destekler, ancak ortaya ekleme/silme O(n) sürer. En temel veri yapısıdır.","nl":"Een datastructuur die elementen van hetzelfde type op aaneengesloten geheugenlocaties opslaat. Ondersteunt O(1) willekeurige toegang via index, maar O(n) voor invoegen/verwijderen in het midden. Meest fundamentele datastructuur.","ru":"Структура данных, хранящая элементы одного типа в смежных ячейках памяти. Поддерживает O(1) произвольный доступ по индексу, но O(n) для вставки/удаления в середине. Самая фундаментальная структура данных.","zh":"一种将相同类型的元素存储在连续内存位置的数据结构。支持通过索引进行O(1)随机访问，但在中间插入/删除为O(n)。最基本的数据结构。","pt_BR":"Uma estrutura de dados que armazena elementos do mesmo tipo em locais de memória contíguos. Suporta acesso aleatório O(1) por índice, mas inserção/exclusão no meio em O(n). A estrutura de dados mais fundamental.","pt_PT":"Uma estrutura de dados que armazena elementos do mesmo tipo em localizações de memória contíguas. Suporta acesso aleatório O(1) por índice, mas inserção/eliminação no meio em O(n). A estrutura de dados mais fundamental."}},
  { id: 'dc-technology-0002', deck_id: 'deck-technology', sort_order: 2, front: "Linked List", back: "A data structure of nodes where each node contains data and a pointer to the next node. O(1) insertion/deletion at known positions but O(n) access by index. No contiguous memory required." , front_translations: {"de":"Verkettete Liste","fr":"Liste chaînée","tr":"Bağlı Liste","nl":"Gelinkte lijst","ru":"Связный список","zh":"链表","pt_BR":"Lista Ligada","pt_PT":"Lista Ligada"}, back_translations: {"de":"Eine Datenstruktur aus Knoten, wobei jeder Knoten Daten und einen Zeiger auf den nächsten Knoten enthält. O(1) Einfügen/Löschen an bekannten Positionen, aber O(n) Zugriff per Index. Kein zusammenhängender Speicher erforderlich.","fr":"Une structure de données composée de nœuds où chaque nœud contient des données et un pointeur vers le nœud suivant. Insertion/suppression en O(1) à des positions connues, mais accès par index en O(n). Aucune mémoire contiguë requise.","tr":"Her düğümün veri ve bir sonraki düğüme işaretçi içerdiği düğümlerden oluşan bir veri yapısı. Bilinen konumlarda O(1) ekleme/silme, ancak indeks ile erişim O(n). Ardışık bellek gerektirmez.","nl":"Een datastructuur van knopen waarbij elke knoop gegevens en een verwijzing naar de volgende knoop bevat. O(1) invoegen/verwijderen op bekende posities, maar O(n) toegang via index. Geen aaneengesloten geheugen vereist.","ru":"Структура данных из узлов, где каждый узел содержит данные и указатель на следующий узел. O(1) вставка/удаление в известных позициях, но O(n) доступ по индексу. Не требует смежной памяти.","zh":"由节点组成的数据结构，每个节点包含数据和指向下一个节点的指针。在已知位置插入/删除为O(1)，但按索引访问为O(n)。不需要连续内存。","pt_BR":"Uma estrutura de dados de nós onde cada nó contém dados e um ponteiro para o próximo nó. Inserção/exclusão em O(1) em posições conhecidas, mas acesso por índice em O(n). Não requer memória contígua.","pt_PT":"Uma estrutura de dados de nós onde cada nó contém dados e um apontador para o nó seguinte. Inserção/eliminação em O(1) em posições conhecidas, mas acesso por índice em O(n). Não requer memória contígua."}},
  { id: 'dc-technology-0003', deck_id: 'deck-technology', sort_order: 3, front: "Doubly Linked List", back: "A linked list where each node has pointers to both the next and previous nodes. Allows O(1) traversal in both directions and efficient deletion of any known node. Uses more memory than singly linked list." , front_translations: {"de":"Doppelt verkettete Liste","fr":"Liste doublement chaînée","tr":"Çift Yönlü Bağlı Liste","nl":"Dubbel gelinkte lijst","ru":"Двусвязный список","zh":"双向链表","pt_BR":"Lista Duplamente Ligada","pt_PT":"Lista Duplamente Ligada"}, back_translations: {"de":"Eine verkettete Liste, bei der jeder Knoten Zeiger auf den nächsten und den vorherigen Knoten hat. Ermöglicht O(1) Traversierung in beide Richtungen und effizientes Löschen beliebiger bekannter Knoten. Verbraucht mehr Speicher als einfach verkettete Liste.","fr":"Une liste chaînée où chaque nœud possède des pointeurs vers le nœud suivant et le nœud précédent. Permet une traversée en O(1) dans les deux sens et la suppression efficace de tout nœud connu. Utilise plus de mémoire qu'une liste simplement chaînée.","tr":"Her düğümün hem sonraki hem de önceki düğüme işaretçi içerdiği bir bağlı liste. Her iki yönde O(1) geçiş ve bilinen herhangi bir düğümün verimli silinmesine olanak tanır. Tek bağlı listeden daha fazla bellek kullanır.","nl":"Een gelinkte lijst waarbij elke knoop verwijzingen heeft naar zowel de volgende als de vorige knoop. Maakt O(1) doorloop in beide richtingen mogelijk en efficiënt verwijderen van elke bekende knoop. Gebruikt meer geheugen dan enkelvoudig gelinkte lijst.","ru":"Связный список, в котором каждый узел имеет указатели на следующий и предыдущий узлы. Позволяет O(1) обход в обоих направлениях и эффективное удаление любого известного узла. Использует больше памяти, чем односвязный список.","zh":"每个节点同时拥有指向下一个和前一个节点指针的链表。允许在两个方向上以O(1)遍历，并能高效删除任意已知节点。比单向链表占用更多内存。","pt_BR":"Uma lista ligada onde cada nó tem ponteiros para o próximo e o anterior. Permite travessia O(1) em ambas as direções e exclusão eficiente de qualquer nó conhecido. Usa mais memória que a lista simplesmente ligada.","pt_PT":"Uma lista ligada onde cada nó tem apontadores para o próximo e o anterior. Permite travessia O(1) em ambas as direções e eliminação eficiente de qualquer nó conhecido. Usa mais memória que a lista simplesmente ligada."}},
  { id: 'dc-technology-0004', deck_id: 'deck-technology', sort_order: 4, front: "Stack", back: "A Last-In-First-Out (LIFO) data structure. Operations: push (add to top), pop (remove from top), peek (view top). Used for function call stacks, undo operations, and expression evaluation." , front_translations: {"de":"Stapel (Stack)","fr":"Pile (Stack)","tr":"Yığın (Stack)","nl":"Stapel (Stack)","ru":"Стек","zh":"栈","pt_BR":"Pilha (Stack)","pt_PT":"Pilha (Stack)"}, back_translations: {"de":"Eine Last-In-First-Out (LIFO) Datenstruktur. Operationen: push (oben hinzufügen), pop (oben entfernen), peek (oben ansehen). Verwendet für Funktionsaufruf-Stacks, Rückgängig-Operationen und Ausdrucksauswertung.","fr":"Une structure de données Last-In-First-Out (LIFO). Opérations : push (ajouter au sommet), pop (retirer du sommet), peek (voir le sommet). Utilisée pour les piles d'appels de fonctions, les opérations d'annulation et l'évaluation d'expressions.","tr":"Son Giren İlk Çıkar (LIFO) veri yapısı. İşlemler: push (üste ekle), pop (üstten çıkar), peek (üstü görüntüle). Fonksiyon çağrı yığınları, geri alma işlemleri ve ifade değerlendirmesi için kullanılır.","nl":"Een Last-In-First-Out (LIFO) datastructuur. Bewerkingen: push (bovenaan toevoegen), pop (bovenaan verwijderen), peek (bovenaan bekijken). Gebruikt voor functie-aanroepstapels, ongedaan maken en expressie-evaluatie.","ru":"Структура данных «последним пришёл — первым ушёл» (LIFO). Операции: push (добавить на вершину), pop (удалить с вершины), peek (просмотреть вершину). Используется для стеков вызовов, отмены операций и вычисления выражений.","zh":"后进先出（LIFO）数据结构。操作：push（添加到顶部）、pop（从顶部移除）、peek（查看顶部）。用于函数调用栈、撤销操作和表达式求值。","pt_BR":"Uma estrutura de dados Last-In-First-Out (LIFO). Operações: push (adicionar ao topo), pop (remover do topo), peek (visualizar topo). Usada para pilhas de chamadas de função, operações de desfazer e avaliação de expressões.","pt_PT":"Uma estrutura de dados Last-In-First-Out (LIFO). Operações: push (adicionar ao topo), pop (remover do topo), peek (ver o topo). Usada para pilhas de chamadas de função, operações de desfazer e avaliação de expressões."}},
  { id: 'dc-technology-0005', deck_id: 'deck-technology', sort_order: 5, front: "Queue", back: "A First-In-First-Out (FIFO) data structure. Operations: enqueue (add to rear), dequeue (remove from front). Used for task scheduling, BFS, and print queues. Deque supports both ends." , front_translations: {"de":"Warteschlange (Queue)","fr":"File d'attente (Queue)","tr":"Kuyruk (Queue)","nl":"Wachtrij (Queue)","ru":"Очередь","zh":"队列","pt_BR":"Fila (Queue)","pt_PT":"Fila (Queue)"}, back_translations: {"de":"Eine First-In-First-Out (FIFO) Datenstruktur. Operationen: enqueue (hinten hinzufügen), dequeue (vorne entfernen). Verwendet für Aufgabenplanung, BFS und Druckwarteschlangen. Deque unterstützt beide Enden.","fr":"Une structure de données First-In-First-Out (FIFO). Opérations : enqueue (ajouter à l'arrière), dequeue (retirer à l'avant). Utilisée pour la planification de tâches, BFS et les files d'impression. Le Deque supporte les deux extrémités.","tr":"İlk Giren İlk Çıkar (FIFO) veri yapısı. İşlemler: enqueue (arkaya ekle), dequeue (önden çıkar). Görev planlama, BFS ve yazdırma kuyrukları için kullanılır. Deque her iki ucu da destekler.","nl":"Een First-In-First-Out (FIFO) datastructuur. Bewerkingen: enqueue (achteraan toevoegen), dequeue (vooraan verwijderen). Gebruikt voor taakplanning, BFS en printerwachtrijen. Deque ondersteunt beide uiteinden.","ru":"Структура данных «первым пришёл — первым ушёл» (FIFO). Операции: enqueue (добавить в конец), dequeue (удалить из начала). Используется для планирования задач, BFS и очередей печати. Deque поддерживает оба конца.","zh":"先进先出（FIFO）数据结构。操作：enqueue（添加到后端）、dequeue（从前端移除）。用于任务调度、BFS和打印队列。双端队列支持两端操作。","pt_BR":"Uma estrutura de dados First-In-First-Out (FIFO). Operações: enqueue (adicionar na traseira), dequeue (remover da frente). Usada para escalonamento de tarefas, BFS e filas de impressão. Deque suporta ambas as extremidades.","pt_PT":"Uma estrutura de dados First-In-First-Out (FIFO). Operações: enqueue (adicionar na traseira), dequeue (remover da frente). Usada para escalonamento de tarefas, BFS e filas de impressão. Deque suporta ambas as extremidades."}},
  { id: 'dc-technology-0006', deck_id: 'deck-technology', sort_order: 6, front: "Hash Table (Hash Map)", back: "A data structure that maps keys to values using a hash function. Average O(1) for insert, delete, and lookup. Collisions resolved by chaining or open addressing. Used for caches, dictionaries, and sets." , front_translations: {"de":"Hash-Tabelle (Hash Map)","fr":"Table de hachage (Hash Map)","tr":"Hash Tablosu (Hash Map)","nl":"Hashtabel (Hash Map)","ru":"Хеш-таблица","zh":"哈希表","pt_BR":"Tabela Hash (Hash Map)","pt_PT":"Tabela de Hash (Hash Map)"}, back_translations: {"de":"Eine Datenstruktur, die Schlüssel mithilfe einer Hash-Funktion auf Werte abbildet. Durchschnittlich O(1) für Einfügen, Löschen und Suchen. Kollisionen werden durch Verkettung oder offenes Adressieren gelöst. Verwendet für Caches, Wörterbücher und Mengen.","fr":"Une structure de données qui associe des clés à des valeurs à l'aide d'une fonction de hachage. O(1) en moyenne pour l'insertion, la suppression et la recherche. Les collisions sont résolues par chaînage ou adressage ouvert. Utilisée pour les caches, dictionnaires et ensembles.","tr":"Bir hash fonksiyonu kullanarak anahtarları değerlere eşleyen veri yapısı. Ekleme, silme ve arama için ortalama O(1). Çakışmalar zincirleme veya açık adresleme ile çözülür. Önbellekler, sözlükler ve kümeler için kullanılır.","nl":"Een datastructuur die sleutels met behulp van een hashfunctie aan waarden koppelt. Gemiddeld O(1) voor invoegen, verwijderen en opzoeken. Botsingen opgelost door chaining of open adressering. Gebruikt voor caches, woordenboeken en verzamelingen.","ru":"Структура данных, сопоставляющая ключи значениям с помощью хеш-функции. В среднем O(1) для вставки, удаления и поиска. Коллизии разрешаются методом цепочек или открытой адресацией. Используется для кешей, словарей и множеств.","zh":"使用哈希函数将键映射到值的数据结构。插入、删除和查找的平均时间为O(1)。通过链接法或开放地址法解决冲突。用于缓存、字典和集合。","pt_BR":"Uma estrutura de dados que mapeia chaves para valores usando uma função hash. Média de O(1) para inserção, exclusão e busca. Colisões resolvidas por encadeamento ou endereçamento aberto. Usada para caches, dicionários e conjuntos.","pt_PT":"Uma estrutura de dados que mapeia chaves para valores usando uma função hash. Média de O(1) para inserção, eliminação e pesquisa. Colisões resolvidas por encadeamento ou endereçamento aberto. Usada para caches, dicionários e conjuntos."}},
  { id: 'dc-technology-0007', deck_id: 'deck-technology', sort_order: 7, front: "Binary Tree", back: "A tree data structure where each node has at most two children (left and right). The basis for binary search trees, heaps, and many algorithms. Traversals: in-order, pre-order, post-order." , front_translations: {"de":"Binärbaum","fr":"Arbre binaire","tr":"İkili Ağaç","nl":"Binaire boom","ru":"Двоичное дерево","zh":"二叉树","pt_BR":"Árvore Binária","pt_PT":"Árvore Binária"}, back_translations: {"de":"Eine Baumdatenstruktur, bei der jeder Knoten höchstens zwei Kinder hat (links und rechts). Die Basis für binäre Suchbäume, Heaps und viele Algorithmen. Traversierungen: In-Order, Pre-Order, Post-Order.","fr":"Une structure de données arborescente où chaque nœud a au plus deux enfants (gauche et droit). La base des arbres de recherche binaire, des tas et de nombreux algorithmes. Parcours : inordre, préordre, postordre.","tr":"Her düğümün en fazla iki çocuğu (sol ve sağ) olan ağaç veri yapısı. İkili arama ağaçları, yığınlar ve birçok algoritmanın temeli. Gezmeler: sıralı, ön sıralı, son sıralı.","nl":"Een boomgegevensstructuur waarbij elke knoop maximaal twee kinderen heeft (links en rechts). De basis voor binaire zoekbomen, heaps en vele algoritmen. Doorloop: in-volgorde, voor-volgorde, na-volgorde.","ru":"Древовидная структура данных, в которой каждый узел имеет не более двух дочерних узлов (левый и правый). Основа для двоичных деревьев поиска, куч и многих алгоритмов. Обходы: симметричный, прямой, обратный.","zh":"每个节点最多有两个子节点（左和右）的树形数据结构。是二叉搜索树、堆和许多算法的基础。遍历方式：中序、前序、后序。","pt_BR":"Uma estrutura de dados em árvore onde cada nó tem no máximo dois filhos (esquerdo e direito). A base para árvores de busca binária, heaps e muitos algoritmos. Travessias: em-ordem, pré-ordem, pós-ordem.","pt_PT":"Uma estrutura de dados em árvore onde cada nó tem no máximo dois filhos (esquerdo e direito). A base para árvores de pesquisa binária, heaps e muitos algoritmos. Travessias: em-ordem, pré-ordem, pós-ordem."}},
  { id: 'dc-technology-0008', deck_id: 'deck-technology', sort_order: 8, front: "Binary Search Tree (BST)", back: "A binary tree where every node's left subtree has values less than the node, and the right subtree has greater values. O(log n) average for search, insert, delete; degrades to O(n) if unbalanced." , front_translations: {"de":"Binärer Suchbaum (BST)","fr":"Arbre binaire de recherche (ABR)","tr":"İkili Arama Ağacı (BST)","nl":"Binaire zoekboom (BST)","ru":"Двоичное дерево поиска (BST)","zh":"二叉搜索树（BST）","pt_BR":"Árvore Binária de Busca (BST)","pt_PT":"Árvore Binária de Pesquisa (BST)"}, back_translations: {"de":"Ein Binärbaum, bei dem der linke Teilbaum jedes Knotens nur kleinere Werte und der rechte Teilbaum nur größere Werte enthält. Durchschnittlich O(log n) für Suche, Einfügen, Löschen; verschlechtert sich auf O(n) bei Unausgewogenheit.","fr":"Un arbre binaire où le sous-arbre gauche de chaque nœud contient des valeurs inférieures et le sous-arbre droit des valeurs supérieures. O(log n) en moyenne pour recherche, insertion, suppression ; se dégrade en O(n) si déséquilibré.","tr":"Her düğümün sol alt ağacının daha küçük, sağ alt ağacının daha büyük değerler içerdiği ikili ağaç. Arama, ekleme, silme için ortalama O(log n); dengesiz ise O(n)'ye düşer.","nl":"Een binaire boom waarbij de linkerdeelboom van elke knoop kleinere waarden bevat en de rechterdeelboom grotere waarden. Gemiddeld O(log n) voor zoeken, invoegen, verwijderen; degradeert naar O(n) bij onbalans.","ru":"Двоичное дерево, в котором левое поддерево каждого узла содержит значения меньше узла, а правое — больше. В среднем O(log n) для поиска, вставки, удаления; ухудшается до O(n) при несбалансированности.","zh":"每个节点的左子树包含比该节点小的值、右子树包含更大值的二叉树。搜索、插入、删除的平均时间为O(log n)；不平衡时退化为O(n)。","pt_BR":"Uma árvore binária onde a subárvore esquerda de cada nó tem valores menores e a direita tem valores maiores. Média de O(log n) para busca, inserção, exclusão; degrada para O(n) se desbalanceada.","pt_PT":"Uma árvore binária onde a subárvore esquerda de cada nó tem valores menores e a direita tem valores maiores. Média de O(log n) para pesquisa, inserção, eliminação; degrada para O(n) se desequilibrada."}},
  { id: 'dc-technology-0009', deck_id: 'deck-technology', sort_order: 9, front: "AVL Tree", back: "A self-balancing BST where the heights of the two child subtrees differ by at most one. Automatically rebalances via rotations after insertions/deletions, guaranteeing O(log n) for all operations." , front_translations: {"de":"AVL-Baum","fr":"Arbre AVL","tr":"AVL Ağacı","nl":"AVL-boom","ru":"АВЛ-дерево","zh":"AVL树","pt_BR":"Árvore AVL","pt_PT":"Árvore AVL"}, back_translations: {"de":"Ein selbstbalancierender BST, bei dem die Höhen der beiden Kindteilbäume um höchstens eins abweichen. Balanciert sich nach Einfügungen/Löschungen automatisch über Rotationen neu, wodurch O(log n) für alle Operationen garantiert wird.","fr":"Un ABR auto-équilibré où les hauteurs des deux sous-arbres enfants diffèrent d'au plus un. Se rééquilibre automatiquement par rotations après insertions/suppressions, garantissant O(log n) pour toutes les opérations.","tr":"İki çocuk alt ağacının yükseklikleri en fazla bir farklı olan dengeli BST. Ekleme/silme sonrası rotasyonlarla otomatik olarak yeniden dengelenir, tüm işlemler için O(log n) garantiler.","nl":"Een zelfbalancerende BST waarbij de hoogten van de twee kinddeelbomen maximaal één verschillen. Herbalanceert automatisch via rotaties na invoegingen/verwijderingen, garandeert O(log n) voor alle bewerkingen.","ru":"Самобалансирующееся BST, в котором высоты двух дочерних поддеревьев отличаются не более чем на единицу. Автоматически перебалансируется через повороты после вставок/удалений, гарантируя O(log n) для всех операций.","zh":"一种自平衡BST，两个子树的高度差最多为1。在插入/删除后通过旋转自动重新平衡，保证所有操作的O(log n)复杂度。","pt_BR":"Uma BST auto-balanceada onde as alturas das duas subárvores filhas diferem em no máximo um. Rebalanceia automaticamente via rotações após inserções/exclusões, garantindo O(log n) para todas as operações.","pt_PT":"Uma BST auto-equilibrada onde as alturas das duas subárvores filhas diferem em no máximo um. Reequilibra automaticamente via rotações após inserções/eliminações, garantindo O(log n) para todas as operações."}},
  { id: 'dc-technology-0010', deck_id: 'deck-technology', sort_order: 10, front: "Red-Black Tree", back: "A self-balancing BST with color properties that ensure the tree remains approximately balanced. Guarantees O(log n) operations. Used in many standard library implementations (Java TreeMap, C++ std::map)." , front_translations: {"de":"Rot-Schwarz-Baum","fr":"Arbre rouge-noir","tr":"Kırmızı-Siyah Ağaç","nl":"Rood-zwart boom","ru":"Красно-чёрное дерево","zh":"红黑树","pt_BR":"Árvore Rubro-Negra","pt_PT":"Árvore Vermelho-Preto"}, back_translations: {"de":"Ein selbstbalancierender BST mit Farbregeln, die sicherstellen, dass der Baum annähernd balanciert bleibt. Garantiert O(log n) Operationen. Verwendet in vielen Standardbibliotheken (Java TreeMap, C++ std::map).","fr":"Un ABR auto-équilibré avec des propriétés de couleur garantissant que l'arbre reste approximativement équilibré. Garantit des opérations en O(log n). Utilisé dans de nombreuses implémentations de bibliothèques standard (Java TreeMap, C++ std::map).","tr":"Ağacın yaklaşık dengeli kalmasını sağlayan renk özelliklerine sahip dengeli BST. O(log n) işlemleri garanti eder. Birçok standart kütüphane uygulamasında kullanılır (Java TreeMap, C++ std::map).","nl":"Een zelfbalancerende BST met kleureigenschappen die ervoor zorgen dat de boom ongeveer gebalanceerd blijft. Garandeert O(log n) bewerkingen. Gebruikt in vele standaardbibliotheken (Java TreeMap, C++ std::map).","ru":"Самобалансирующееся BST с цветовыми свойствами, обеспечивающими приближённую сбалансированность дерева. Гарантирует O(log n) операции. Используется во многих реализациях стандартных библиотек (Java TreeMap, C++ std::map).","zh":"一种具有颜色属性的自平衡BST，确保树保持近似平衡。保证O(log n)操作。用于许多标准库实现（Java TreeMap、C++ std::map）。","pt_BR":"Uma BST auto-balanceada com propriedades de cor que garantem que a árvore permaneça aproximadamente balanceada. Garante operações O(log n). Usada em muitas implementações de biblioteca padrão (Java TreeMap, C++ std::map).","pt_PT":"Uma BST auto-equilibrada com propriedades de cor que garantem que a árvore permaneça aproximadamente equilibrada. Garante operações O(log n). Usada em muitas implementações de biblioteca padrão (Java TreeMap, C++ std::map)."}},
  { id: 'dc-technology-0011', deck_id: 'deck-technology', sort_order: 11, front: "Heap", back: "A complete binary tree satisfying the heap property: in a max-heap, every parent is ≥ its children; in a min-heap, every parent is ≤ its children. Enables O(1) access to the max/min and O(log n) insert/delete." , front_translations: {"de":"Heap","fr":"Tas (Heap)","tr":"Yığın (Heap)","nl":"Heap","ru":"Куча (Heap)","zh":"堆","pt_BR":"Heap","pt_PT":"Heap"}, back_translations: {"de":"Ein vollständiger Binärbaum, der die Heap-Eigenschaft erfüllt: in einem Max-Heap ist jedes Elternteil ≥ seine Kinder; in einem Min-Heap ist jedes Elternteil ≤ seine Kinder. Ermöglicht O(1) Zugriff auf Max/Min und O(log n) Einfügen/Löschen.","fr":"Un arbre binaire complet satisfaisant la propriété de tas : dans un tas max, chaque parent est ≥ ses enfants ; dans un tas min, chaque parent est ≤ ses enfants. Permet un accès O(1) au max/min et une insertion/suppression en O(log n).","tr":"Yığın özelliğini sağlayan tam ikili ağaç: max-yığında her ebeveyn ≥ çocukları; min-yığında her ebeveyn ≤ çocukları. Max/min'e O(1) erişim ve O(log n) ekleme/silme sağlar.","nl":"Een volledige binaire boom die de heapeigenschap satisficeert: in een max-heap is elke ouder ≥ zijn kinderen; in een min-heap is elke ouder ≤ zijn kinderen. Maakt O(1) toegang tot max/min en O(log n) invoegen/verwijderen mogelijk.","ru":"Полное двоичное дерево, удовлетворяющее свойству кучи: в max-куче каждый родитель ≥ своих потомков; в min-куче каждый родитель ≤ своих потомков. Обеспечивает O(1) доступ к max/min и O(log n) вставку/удаление.","zh":"满足堆性质的完全二叉树：在最大堆中，每个父节点≥其子节点；在最小堆中，每个父节点≤其子节点。支持O(1)访问最大/最小值和O(log n)插入/删除。","pt_BR":"Uma árvore binária completa satisfazendo a propriedade de heap: em um max-heap, todo pai é ≥ seus filhos; em um min-heap, todo pai é ≤ seus filhos. Permite acesso O(1) ao max/min e inserção/exclusão em O(log n).","pt_PT":"Uma árvore binária completa satisfazendo a propriedade de heap: num max-heap, cada pai é ≥ seus filhos; num min-heap, cada pai é ≤ seus filhos. Permite acesso O(1) ao max/min e inserção/eliminação em O(log n)."}},
  { id: 'dc-technology-0012', deck_id: 'deck-technology', sort_order: 12, front: "Graph", back: "A data structure of vertices (nodes) connected by edges. Can be directed or undirected, weighted or unweighted. Used to model networks, dependencies, maps, and social connections." , front_translations: {"de":"Graph","fr":"Graphe","tr":"Graf","nl":"Graaf","ru":"Граф","zh":"图","pt_BR":"Grafo","pt_PT":"Grafo"}, back_translations: {"de":"Eine Datenstruktur aus Knoten (Vertices), die durch Kanten verbunden sind. Kann gerichtet oder ungerichtet, gewichtet oder ungewichtet sein. Verwendet zur Modellierung von Netzwerken, Abhängigkeiten, Karten und sozialen Verbindungen.","fr":"Une structure de données composée de sommets (nœuds) reliés par des arêtes. Peut être orienté ou non orienté, pondéré ou non pondéré. Utilisé pour modéliser des réseaux, des dépendances, des cartes et des connexions sociales.","tr":"Kenarlarla bağlanan köşelerden (düğümler) oluşan veri yapısı. Yönlü veya yönsüz, ağırlıklı veya ağırlıksız olabilir. Ağları, bağımlılıkları, haritaları ve sosyal bağlantıları modellemek için kullanılır.","nl":"Een datastructuur van hoekpunten (knopen) verbonden door kanten. Kan gericht of ongericht, gewogen of ongewogen zijn. Gebruikt om netwerken, afhankelijkheden, kaarten en sociale verbindingen te modelleren.","ru":"Структура данных из вершин (узлов), соединённых рёбрами. Может быть ориентированным или неориентированным, взвешенным или невзвешенным. Используется для моделирования сетей, зависимостей, карт и социальных связей.","zh":"由通过边连接的顶点（节点）组成的数据结构。可以是有向或无向、加权或无权的。用于建模网络、依赖关系、地图和社交连接。","pt_BR":"Uma estrutura de dados de vértices (nós) conectados por arestas. Pode ser dirigido ou não dirigido, ponderado ou não ponderado. Usado para modelar redes, dependências, mapas e conexões sociais.","pt_PT":"Uma estrutura de dados de vértices (nós) ligados por arestas. Pode ser dirigido ou não dirigido, ponderado ou não ponderado. Usado para modelar redes, dependências, mapas e ligações sociais."}},
  { id: 'dc-technology-0013', deck_id: 'deck-technology', sort_order: 13, front: "Graph: Adjacency Matrix vs. Adjacency List", back: "Adjacency matrix: O(V²) space, O(1) edge lookup. Adjacency list: O(V+E) space, O(degree) edge lookup. Lists are preferred for sparse graphs; matrices for dense graphs or frequent edge queries." , front_translations: {"de":"Graph: Adjazenzmatrix vs. Adjazenzliste","fr":"Graphe : Matrice d'adjacence vs. Liste d'adjacence","tr":"Graf: Komşuluk Matrisi vs. Komşuluk Listesi","nl":"Graaf: Aangrenzingsmatrix vs. Aangrenzingslijst","ru":"Граф: матрица смежности vs. список смежности","zh":"图：邻接矩阵 vs. 邻接表","pt_BR":"Grafo: Matriz de Adjacência vs. Lista de Adjacência","pt_PT":"Grafo: Matriz de Adjacência vs. Lista de Adjacência"}, back_translations: {"de":"Adjazenzmatrix: O(V²) Speicher, O(1) Kantenabfrage. Adjazenzliste: O(V+E) Speicher, O(Grad) Kantenabfrage. Listen bevorzugt für dünn besetzte Graphen; Matrizen für dichte Graphen oder häufige Kantenabfragen.","fr":"Matrice d'adjacence : espace O(V²), consultation d'arête O(1). Liste d'adjacence : espace O(V+E), consultation d'arête O(degré). Les listes sont préférées pour les graphes creux ; les matrices pour les graphes denses ou les requêtes d'arêtes fréquentes.","tr":"Komşuluk matrisi: O(V²) alan, O(1) kenar sorgusu. Komşuluk listesi: O(V+E) alan, O(derece) kenar sorgusu. Listeler seyrek graflar için tercih edilir; matrisler yoğun graflar veya sık kenar sorguları için.","nl":"Aangrenzingsmatrix: O(V²) ruimte, O(1) kantopzoekingen. Aangrenzingslijst: O(V+E) ruimte, O(graad) kantopzoekingen. Lijsten zijn te verkiezen voor ijle grafen; matrices voor dichte grafen of frequente kantopzoekingen.","ru":"Матрица смежности: O(V²) памяти, O(1) для поиска ребра. Список смежности: O(V+E) памяти, O(степень) для поиска ребра. Списки предпочтительны для разреженных графов; матрицы — для плотных или частых запросов рёбер.","zh":"邻接矩阵：O(V²)空间，O(1)边查询。邻接表：O(V+E)空间，O(度)边查询。稀疏图倾向于使用列表；密集图或频繁边查询时使用矩阵。","pt_BR":"Matriz de adjacência: espaço O(V²), busca de aresta O(1). Lista de adjacência: espaço O(V+E), busca de aresta O(grau). Listas preferidas para grafos esparsos; matrizes para grafos densos ou consultas frequentes de arestas.","pt_PT":"Matriz de adjacência: espaço O(V²), pesquisa de aresta O(1). Lista de adjacência: espaço O(V+E), pesquisa de aresta O(grau). Listas preferidas para grafos esparsos; matrizes para grafos densos ou consultas frequentes de arestas."}},
  { id: 'dc-technology-0014', deck_id: 'deck-technology', sort_order: 14, front: "Trie (Prefix Tree)", back: "A tree where each node represents a character; paths from root to node represent strings. Efficient for prefix searches, autocomplete, and spell-checking. O(L) for search/insert where L is word length." , front_translations: {"de":"Trie (Präfixbaum)","fr":"Trie (Arbre préfixe)","tr":"Trie (Önek Ağacı)","nl":"Trie (Prefixboom)","ru":"Префиксное дерево (Trie)","zh":"字典树（Trie）","pt_BR":"Trie (Árvore de Prefixo)","pt_PT":"Trie (Árvore de Prefixo)"}, back_translations: {"de":"Ein Baum, bei dem jeder Knoten ein Zeichen darstellt; Pfade von der Wurzel zum Knoten repräsentieren Zeichenketten. Effizient für Präfixsuchen, Autovervollständigung und Rechtschreibprüfung. O(L) für Suche/Einfügen, wobei L die Wortlänge ist.","fr":"Un arbre où chaque nœud représente un caractère ; les chemins de la racine au nœud représentent des chaînes. Efficace pour les recherches par préfixe, la complétion automatique et la vérification orthographique. O(L) pour recherche/insertion où L est la longueur du mot.","tr":"Her düğümün bir karakteri temsil ettiği ağaç; kökten düğüme giden yollar dizeleri temsil eder. Önek aramaları, otomatik tamamlama ve yazım denetimi için verimli. L kelime uzunluğu olmak üzere arama/ekleme için O(L).","nl":"Een boom waarbij elke knoop een teken vertegenwoordigt; paden van wortel naar knoop stellen strings voor. Efficiënt voor voorvoegsels zoeken, autocomplete en spellingcontrole. O(L) voor zoeken/invoegen waarbij L de woordlengte is.","ru":"Дерево, в котором каждый узел представляет символ; пути от корня до узла представляют строки. Эффективно для поиска по префиксу, автодополнения и проверки орфографии. O(L) для поиска/вставки, где L — длина слова.","zh":"每个节点代表一个字符的树；从根到节点的路径代表字符串。适用于前缀搜索、自动补全和拼写检查。搜索/插入为O(L)，其中L是单词长度。","pt_BR":"Uma árvore onde cada nó representa um caractere; caminhos da raiz ao nó representam strings. Eficiente para buscas de prefixo, autocompletar e verificação ortográfica. O(L) para busca/inserção onde L é o comprimento da palavra.","pt_PT":"Uma árvore onde cada nó representa um carácter; caminhos da raiz ao nó representam strings. Eficiente para pesquisas de prefixo, autocompletar e verificação ortográfica. O(L) para pesquisa/inserção onde L é o comprimento da palavra."}},
  { id: 'dc-technology-0015', deck_id: 'deck-technology', sort_order: 15, front: "Big O Notation", back: "A mathematical notation describing the upper bound of algorithm complexity (time or space) in the worst case as input size grows. O(1) is constant, O(n) is linear, O(n²) is quadratic." , front_translations: {"de":"Big-O-Notation","fr":"Notation grand O","tr":"Büyük O Notasyonu","nl":"Big O-notatie","ru":"Нотация «O» большое","zh":"大O符号","pt_BR":"Notação Big O","pt_PT":"Notação Big O"}, back_translations: {"de":"Eine mathematische Notation, die die obere Schranke der Algorithmuskomplexität (Zeit oder Speicher) im schlimmsten Fall beschreibt, wenn die Eingabegröße wächst. O(1) ist konstant, O(n) ist linear, O(n²) ist quadratisch.","fr":"Une notation mathématique décrivant la borne supérieure de la complexité d'un algorithme (temps ou espace) dans le pire cas à mesure que la taille de l'entrée croît. O(1) est constant, O(n) est linéaire, O(n²) est quadratique.","tr":"Giriş boyutu büyüdükçe en kötü durumda algoritma karmaşıklığının (zaman veya alan) üst sınırını açıklayan matematiksel notasyon. O(1) sabit, O(n) doğrusal, O(n²) kareseldir.","nl":"Een wiskundige notatie die de bovengrens van algoritmecomplexiteit (tijd of ruimte) in het slechtste geval beschrijft naarmate de invoergrootte groeit. O(1) is constant, O(n) is lineair, O(n²) is kwadratisch.","ru":"Математическая нотация, описывающая верхнюю границу сложности алгоритма (по времени или памяти) в худшем случае при росте размера входных данных. O(1) — константа, O(n) — линейная, O(n²) — квадратичная.","zh":"一种数学符号，描述算法复杂度（时间或空间）在最坏情况下随输入规模增长的上界。O(1)是常数，O(n)是线性，O(n²)是二次方。","pt_BR":"Uma notação matemática descrevendo o limite superior da complexidade do algoritmo (tempo ou espaço) no pior caso à medida que o tamanho da entrada cresce. O(1) é constante, O(n) é linear, O(n²) é quadrático.","pt_PT":"Uma notação matemática que descreve o limite superior da complexidade do algoritmo (tempo ou espaço) no pior caso à medida que o tamanho da entrada cresce. O(1) é constante, O(n) é linear, O(n²) é quadrático."}},
  { id: 'dc-technology-0016', deck_id: 'deck-technology', sort_order: 16, front: "Time Complexity Classes", back: "O(1) constant, O(log n) logarithmic, O(n) linear, O(n log n) linearithmic, O(n²) quadratic, O(2ⁿ) exponential, O(n!) factorial. Each class grows significantly faster than the previous." , front_translations: {"de":"Zeitkomplexitätsklassen","fr":"Classes de complexité temporelle","tr":"Zaman Karmaşıklığı Sınıfları","nl":"Tijdcomplexiteitsklassen","ru":"Классы временной сложности","zh":"时间复杂度类","pt_BR":"Classes de Complexidade de Tempo","pt_PT":"Classes de Complexidade de Tempo"}, back_translations: {"de":"O(1) konstant, O(log n) logarithmisch, O(n) linear, O(n log n) linearithmisch, O(n²) quadratisch, O(2ⁿ) exponentiell, O(n!) faktoriell. Jede Klasse wächst deutlich schneller als die vorherige.","fr":"O(1) constant, O(log n) logarithmique, O(n) linéaire, O(n log n) linéarithmique, O(n²) quadratique, O(2ⁿ) exponentiel, O(n!) factoriel. Chaque classe croît significativement plus vite que la précédente.","tr":"O(1) sabit, O(log n) logaritmik, O(n) doğrusal, O(n log n) doğrusal-logaritmik, O(n²) karesel, O(2ⁿ) üstel, O(n!) faktöriyel. Her sınıf bir öncekinden önemli ölçüde daha hızlı büyür.","nl":"O(1) constant, O(log n) logaritmisch, O(n) lineair, O(n log n) lineair-logaritmisch, O(n²) kwadratisch, O(2ⁿ) exponentieel, O(n!) faculteit. Elke klasse groeit aanzienlijk sneller dan de vorige.","ru":"O(1) — константа, O(log n) — логарифмическая, O(n) — линейная, O(n log n) — линейно-логарифмическая, O(n²) — квадратичная, O(2ⁿ) — экспоненциальная, O(n!) — факториальная. Каждый класс растёт значительно быстрее предыдущего.","zh":"O(1)常数，O(log n)对数，O(n)线性，O(n log n)线性对数，O(n²)二次方，O(2ⁿ)指数，O(n!)阶乘。每个类别的增长速度都显著快于前一个。","pt_BR":"O(1) constante, O(log n) logarítmico, O(n) linear, O(n log n) linearítmico, O(n²) quadrático, O(2ⁿ) exponencial, O(n!) fatorial. Cada classe cresce significativamente mais rápido que a anterior.","pt_PT":"O(1) constante, O(log n) logarítmico, O(n) linear, O(n log n) linearítmico, O(n²) quadrático, O(2ⁿ) exponencial, O(n!) fatorial. Cada classe cresce significativamente mais rápido que a anterior."}},
  { id: 'dc-technology-0017', deck_id: 'deck-technology', sort_order: 17, front: "Binary Search", back: "An efficient search algorithm for sorted arrays that repeatedly halves the search space. Time complexity O(log n), far faster than linear search O(n) for large datasets." , front_translations: {"de":"Binäre Suche","fr":"Recherche binaire","tr":"İkili Arama","nl":"Binair zoeken","ru":"Двоичный поиск","zh":"二分搜索","pt_BR":"Busca Binária","pt_PT":"Pesquisa Binária"}, back_translations: {"de":"Ein effizienter Suchalgorithmus für sortierte Arrays, der den Suchraum wiederholt halbiert. Zeitkomplexität O(log n), viel schneller als lineare Suche O(n) bei großen Datensätzen.","fr":"Un algorithme de recherche efficace pour les tableaux triés qui divise répétitivement l'espace de recherche en deux. Complexité temporelle O(log n), bien plus rapide que la recherche linéaire O(n) pour de grands ensembles de données.","tr":"Arama alanını tekrar tekrar yarıya indiren sıralı diziler için verimli arama algoritması. Zaman karmaşıklığı O(log n), büyük veri kümeleri için doğrusal arama O(n)'den çok daha hızlı.","nl":"Een efficiënt zoekalgoritme voor gesorteerde arrays dat de zoekruimte herhaaldelijk halveert. Tijdcomplexiteit O(log n), veel sneller dan lineair zoeken O(n) voor grote datasets.","ru":"Эффективный алгоритм поиска в отсортированных массивах, многократно разделяющий пространство поиска пополам. Временная сложность O(log n), намного быстрее линейного поиска O(n) для больших наборов данных.","zh":"一种在有序数组中通过反复将搜索空间减半的高效搜索算法。时间复杂度O(log n)，对于大数据集远快于线性搜索O(n)。","pt_BR":"Um algoritmo de busca eficiente para arrays ordenados que divide repetidamente o espaço de busca pela metade. Complexidade de tempo O(log n), muito mais rápido que a busca linear O(n) para grandes conjuntos de dados.","pt_PT":"Um algoritmo de pesquisa eficiente para arrays ordenados que divide repetidamente o espaço de pesquisa ao meio. Complexidade de tempo O(log n), muito mais rápido que a pesquisa linear O(n) para grandes conjuntos de dados."}},
  { id: 'dc-technology-0018', deck_id: 'deck-technology', sort_order: 18, front: "Bubble Sort", back: "A simple sorting algorithm that repeatedly swaps adjacent elements in the wrong order. O(n²) average and worst case. O(n) best case (already sorted with optimization). Rarely used in practice." , front_translations: {"de":"Bubble Sort","fr":"Tri à bulles","tr":"Kabarcık Sıralama","nl":"Bubbelsorteeralgoritme","ru":"Сортировка пузырьком","zh":"冒泡排序","pt_BR":"Ordenação por Bolha","pt_PT":"Ordenação por Bolha"}, back_translations: {"de":"Ein einfacher Sortieralgorithmus, der benachbarte Elemente in der falschen Reihenfolge wiederholt vertauscht. O(n²) im Durchschnitt und im schlechtesten Fall. O(n) im besten Fall (bereits sortiert mit Optimierung). In der Praxis selten verwendet.","fr":"Un algorithme de tri simple qui échange répétitivement les éléments adjacents dans le mauvais ordre. O(n²) en moyenne et dans le pire cas. O(n) dans le meilleur cas (déjà trié avec optimisation). Rarement utilisé en pratique.","tr":"Yanlış sıradaki komşu elemanları tekrar tekrar değiştiren basit sıralama algoritması. Ortalama ve en kötü durum O(n²). En iyi durum O(n) (optimizasyonla zaten sıralı). Pratikte nadiren kullanılır.","nl":"Een eenvoudig sorteeralgoritme dat herhaaldelijk aangrenzende elementen in de verkeerde volgorde verwisselt. O(n²) gemiddeld en in het slechtste geval. O(n) in het beste geval (al gesorteerd met optimalisatie). Zelden gebruikt in de praktijk.","ru":"Простой алгоритм сортировки, многократно меняющий местами соседние элементы в неправильном порядке. O(n²) в среднем и худшем случае. O(n) в лучшем случае (уже отсортировано с оптимизацией). Редко используется на практике.","zh":"一种简单的排序算法，反复交换相邻的错误顺序元素。平均和最坏情况O(n²)。最佳情况O(n)（已排序并优化）。实践中很少使用。","pt_BR":"Um algoritmo de ordenação simples que troca repetidamente elementos adjacentes na ordem errada. O(n²) no caso médio e pior caso. O(n) no melhor caso (já ordenado com otimização). Raramente usado na prática.","pt_PT":"Um algoritmo de ordenação simples que troca repetidamente elementos adjacentes na ordem errada. O(n²) no caso médio e pior caso. O(n) no melhor caso (já ordenado com otimização). Raramente usado na prática."}},
  { id: 'dc-technology-0019', deck_id: 'deck-technology', sort_order: 19, front: "Selection Sort", back: "Sorts by repeatedly selecting the minimum element and placing it at the front. O(n²) for all cases. Makes fewer swaps than bubble sort; simple but inefficient for large datasets." , front_translations: {"de":"Auswahlsortierung","fr":"Tri par sélection","tr":"Seçimli Sıralama","nl":"Selectiesorteeralgoritme","ru":"Сортировка выбором","zh":"选择排序","pt_BR":"Ordenação por Seleção","pt_PT":"Ordenação por Seleção"}, back_translations: {"de":"Sortiert, indem das Minimum wiederholt ausgewählt und an den Anfang gestellt wird. O(n²) für alle Fälle. Macht weniger Vertauschungen als Bubble Sort; einfach, aber ineffizient für große Datensätze.","fr":"Trie en sélectionnant répétitivement l'élément minimum et en le plaçant au début. O(n²) dans tous les cas. Effectue moins d'échanges que le tri à bulles ; simple mais inefficace pour de grands ensembles de données.","tr":"Minimum elemanı tekrar tekrar seçerek öne yerleştirerek sıralama yapar. Tüm durumlar için O(n²). Kabarcık sıralamadan daha az değiştirme yapar; basit ama büyük veri kümeleri için verimsiz.","nl":"Sorteert door herhaaldelijk het minimale element te selecteren en vooraan te plaatsen. O(n²) voor alle gevallen. Maakt minder swaps dan bubbelsorteeralgoritme; eenvoudig maar inefficiënt voor grote datasets.","ru":"Сортирует, многократно выбирая минимальный элемент и помещая его в начало. O(n²) для всех случаев. Делает меньше перестановок, чем пузырьковая сортировка; простой, но неэффективный для больших наборов данных.","zh":"通过反复选择最小元素并将其放在前面来排序。所有情况下均为O(n²)。比冒泡排序交换次数少；简单但对大数据集效率低。","pt_BR":"Ordena selecionando repetidamente o elemento mínimo e colocando-o na frente. O(n²) para todos os casos. Faz menos trocas que a ordenação por bolha; simples mas ineficiente para grandes conjuntos de dados.","pt_PT":"Ordena selecionando repetidamente o elemento mínimo e colocando-o na frente. O(n²) para todos os casos. Faz menos trocas que a ordenação por bolha; simples mas ineficiente para grandes conjuntos de dados."}},
  { id: 'dc-technology-0020', deck_id: 'deck-technology', sort_order: 20, front: "Insertion Sort", back: "Builds a sorted array one element at a time by inserting each element into its correct position. O(n²) worst case but O(n) for nearly sorted input. Efficient for small or nearly sorted arrays." , front_translations: {"de":"Einfügesortierung","fr":"Tri par insertion","tr":"Eklemeli Sıralama","nl":"Invoegsorteren","ru":"Сортировка вставками","zh":"插入排序","pt_BR":"Ordenação por Inserção","pt_PT":"Ordenação por Inserção"}, back_translations: {"de":"Erstellt ein sortiertes Array Element für Element, indem jedes Element an seiner richtigen Position eingefügt wird. O(n²) im schlechtesten Fall, aber O(n) für nahezu sortierte Eingaben. Effizient für kleine oder nahezu sortierte Arrays.","fr":"Construit un tableau trié un élément à la fois en insérant chaque élément à sa position correcte. O(n²) dans le pire cas mais O(n) pour une entrée presque triée. Efficace pour les petits tableaux ou presque triés.","tr":"Her elemanı doğru konumuna ekleyerek sıralı diziyi tek tek oluşturur. En kötü durum O(n²), ancak neredeyse sıralı giriş için O(n). Küçük veya neredeyse sıralı diziler için verimli.","nl":"Bouwt een gesorteerde array één element tegelijk door elk element op de juiste positie in te voegen. O(n²) in het slechtste geval maar O(n) voor bijna gesorteerde invoer. Efficiënt voor kleine of bijna gesorteerde arrays.","ru":"Строит отсортированный массив по одному элементу, вставляя каждый элемент на правильную позицию. O(n²) в худшем случае, но O(n) для почти отсортированных данных. Эффективна для малых или почти отсортированных массивов.","zh":"通过将每个元素插入正确位置来逐个构建排序数组。最坏情况O(n²)，但对于接近有序的输入为O(n)。对小型或接近有序的数组效率高。","pt_BR":"Constrói um array ordenado um elemento de cada vez, inserindo cada elemento em sua posição correta. O(n²) no pior caso mas O(n) para entrada quase ordenada. Eficiente para arrays pequenos ou quase ordenados.","pt_PT":"Constrói um array ordenado um elemento de cada vez, inserindo cada elemento na sua posição correta. O(n²) no pior caso mas O(n) para entrada quase ordenada. Eficiente para arrays pequenos ou quase ordenados."}},
  { id: 'dc-technology-0021', deck_id: 'deck-technology', sort_order: 21, front: "Merge Sort", back: "A divide-and-conquer sorting algorithm that divides the array in half, sorts each half recursively, then merges. O(n log n) guaranteed. Stable and excellent for linked lists but requires O(n) extra space." , front_translations: {"de":"Merge Sort","fr":"Tri fusion","tr":"Birleştirme Sıralaması","nl":"Merge sort","ru":"Сортировка слиянием","zh":"归并排序","pt_BR":"Ordenação por Fusão","pt_PT":"Ordenação por Fusão"}, back_translations: {"de":"Ein Teile-und-Herrsche-Sortieralgorithmus, der das Array halbiert, jede Hälfte rekursiv sortiert und dann zusammenführt. O(n log n) garantiert. Stabil und ausgezeichnet für verkettete Listen, erfordert jedoch O(n) zusätzlichen Speicher.","fr":"Un algorithme de tri diviser-pour-régner qui divise le tableau en deux, trie chaque moitié récursivement, puis les fusionne. O(n log n) garanti. Stable et excellent pour les listes chaînées mais nécessite un espace supplémentaire O(n).","tr":"Diziyi yarıya bölen, her yarıyı özyinelemeli olarak sıralayan, ardından birleştiren böl ve yönet sıralama algoritması. O(n log n) garantili. Kararlı ve bağlı listeler için mükemmel, ancak O(n) ekstra alan gerektirir.","nl":"Een verdeel-en-heers sorteeralgoritme dat de array halveert, elke helft recursief sorteert en dan samenvoegt. O(n log n) gegarandeerd. Stabiel en uitstekend voor gelinkte lijsten maar vereist O(n) extra ruimte.","ru":"Алгоритм сортировки «разделяй и властвуй», который делит массив пополам, рекурсивно сортирует каждую половину, затем объединяет. O(n log n) гарантировано. Стабильный и отличный для связных списков, но требует O(n) дополнительной памяти.","zh":"一种分治排序算法，将数组分成两半，递归地对每一半排序，然后合并。保证O(n log n)。稳定，非常适合链表，但需要O(n)额外空间。","pt_BR":"Um algoritmo de ordenação de divisão e conquista que divide o array ao meio, ordena cada metade recursivamente e então mescla. O(n log n) garantido. Estável e excelente para listas ligadas, mas requer O(n) de espaço extra.","pt_PT":"Um algoritmo de ordenação de divisão e conquista que divide o array ao meio, ordena cada metade recursivamente e depois funde. O(n log n) garantido. Estável e excelente para listas ligadas, mas requer O(n) de espaço extra."}},
  { id: 'dc-technology-0022', deck_id: 'deck-technology', sort_order: 22, front: "Quick Sort", back: "A divide-and-conquer algorithm that picks a pivot and partitions elements. O(n log n) average, O(n²) worst case (poor pivot choice). Typically fastest in practice; in-place; not stable." , front_translations: {"de":"Quick Sort","fr":"Tri rapide","tr":"Hızlı Sıralama","nl":"Quicksort","ru":"Быстрая сортировка","zh":"快速排序","pt_BR":"Ordenação Rápida","pt_PT":"Ordenação Rápida"}, back_translations: {"de":"Ein Teile-und-Herrsche-Algorithmus, der ein Pivot-Element wählt und Elemente partitioniert. Durchschnittlich O(n log n), O(n²) im schlechtesten Fall (schlechte Pivot-Wahl). Typischerweise der schnellste in der Praxis; in-place; nicht stabil.","fr":"Un algorithme diviser-pour-régner qui choisit un pivot et partitionne les éléments. O(n log n) en moyenne, O(n²) dans le pire cas (mauvais choix de pivot). Généralement le plus rapide en pratique ; en place ; non stable.","tr":"Pivot seçip elemanları bölen böl ve yönet algoritması. Ortalama O(n log n), en kötü durum O(n²) (kötü pivot seçimi). Pratikte genellikle en hızlı; yerinde; kararlı değil.","nl":"Een verdeel-en-heers algoritme dat een spilelement kiest en elementen partitioneert. Gemiddeld O(n log n), O(n²) in het slechtste geval (slechte pivotkeuze). Typisch het snelst in de praktijk; in-place; niet stabiel.","ru":"Алгоритм «разделяй и властвуй», выбирающий опорный элемент и разбивающий массив. В среднем O(n log n), O(n²) в худшем случае (неудачный выбор опорного). Обычно быстрейший на практике; in-place; нестабильный.","zh":"一种选择基准元素并对元素进行分区的分治算法。平均O(n log n)，最坏情况O(n²)（糟糕的基准选择）。实践中通常最快；原地排序；不稳定。","pt_BR":"Um algoritmo de divisão e conquista que escolhe um pivô e particiona os elementos. Média O(n log n), O(n²) no pior caso (escolha ruim de pivô). Tipicamente o mais rápido na prática; in-place; não estável.","pt_PT":"Um algoritmo de divisão e conquista que escolhe um pivô e particiona os elementos. Média O(n log n), O(n²) no pior caso (escolha má de pivô). Tipicamente o mais rápido na prática; in-place; não estável."}},
  { id: 'dc-technology-0023', deck_id: 'deck-technology', sort_order: 23, front: "Heap Sort", back: "Builds a max-heap then repeatedly extracts the maximum to produce a sorted array. O(n log n) guaranteed, in-place. Not stable; in practice slower than quicksort due to poor cache performance." , front_translations: {"de":"Heap Sort","fr":"Tri par tas","tr":"Yığın Sıralaması","nl":"Heapsorteeralgoritme","ru":"Пирамидальная сортировка","zh":"堆排序","pt_BR":"Ordenação por Heap","pt_PT":"Ordenação por Heap"}, back_translations: {"de":"Erstellt einen Max-Heap und extrahiert dann wiederholt das Maximum, um ein sortiertes Array zu erzeugen. O(n log n) garantiert, in-place. Nicht stabil; in der Praxis langsamer als Quicksort aufgrund schlechter Cache-Performance.","fr":"Construit un tas max puis extrait répétitivement le maximum pour produire un tableau trié. O(n log n) garanti, en place. Non stable ; en pratique plus lent que le tri rapide en raison des mauvaises performances du cache.","tr":"Max-yığın oluşturur, ardından sıralı dizi üretmek için maksimumu tekrar tekrar çıkarır. O(n log n) garantili, yerinde. Kararlı değil; pratikte zayıf önbellek performansı nedeniyle quicksort'tan daha yavaş.","nl":"Bouwt een max-heap en extraheert dan herhaaldelijk het maximum om een gesorteerde array te produceren. O(n log n) gegarandeerd, in-place. Niet stabiel; in de praktijk langzamer dan quicksort vanwege slechte cache-prestaties.","ru":"Строит max-кучу, затем многократно извлекает максимум для получения отсортированного массива. O(n log n) гарантировано, in-place. Нестабильный; на практике медленнее быстрой сортировки из-за плохой работы с кешем.","zh":"构建最大堆，然后反复提取最大值以产生排序数组。保证O(n log n)，原地排序。不稳定；由于缓存性能差，实践中比快速排序慢。","pt_BR":"Constrói um max-heap e então extrai repetidamente o máximo para produzir um array ordenado. O(n log n) garantido, in-place. Não estável; na prática mais lento que quicksort devido ao fraco desempenho de cache.","pt_PT":"Constrói um max-heap e depois extrai repetidamente o máximo para produzir um array ordenado. O(n log n) garantido, in-place. Não estável; na prática mais lento que quicksort devido ao fraco desempenho de cache."}},
  { id: 'dc-technology-0024', deck_id: 'deck-technology', sort_order: 24, front: "Counting Sort", back: "A non-comparison sort that counts occurrences of each value and reconstructs the sorted array. O(n+k) where k is the range of values. Efficient when k is small relative to n; not suitable for large ranges." , front_translations: {"de":"Zählsortierung","fr":"Tri par comptage","tr":"Sayma Sıralaması","nl":"Telsorteeralgoritme","ru":"Сортировка подсчётом","zh":"计数排序","pt_BR":"Ordenação por Contagem","pt_PT":"Ordenação por Contagem"}, back_translations: {"de":"Eine nicht-vergleichsbasierte Sortierung, die Vorkommen jedes Werts zählt und das sortierte Array rekonstruiert. O(n+k), wobei k der Wertebereich ist. Effizient, wenn k klein relativ zu n ist; nicht geeignet für große Bereiche.","fr":"Un tri non comparatif qui compte les occurrences de chaque valeur et reconstruit le tableau trié. O(n+k) où k est la plage de valeurs. Efficace quand k est petit par rapport à n ; inadapté aux grandes plages.","tr":"Her değerin oluşumlarını sayan ve sıralı diziyi yeniden oluşturan karşılaştırmasız sıralama. k değer aralığı olmak üzere O(n+k). k, n'ye göre küçük olduğunda verimli; büyük aralıklar için uygun değil.","nl":"Een niet-vergelijkende sortering die het voorkomen van elke waarde telt en de gesorteerde array reconstrueert. O(n+k) waarbij k het waardenbereik is. Efficiënt wanneer k klein is ten opzichte van n; niet geschikt voor grote bereiken.","ru":"Несравнительная сортировка, подсчитывающая вхождения каждого значения и восстанавливающая отсортированный массив. O(n+k), где k — диапазон значений. Эффективна, когда k мало по сравнению с n; не подходит для больших диапазонов.","zh":"一种非比较排序，统计每个值的出现次数并重建排序数组。O(n+k)，其中k是值的范围。当k相对于n较小时效率高；不适用于大范围。","pt_BR":"Uma ordenação não comparativa que conta ocorrências de cada valor e reconstrói o array ordenado. O(n+k) onde k é o intervalo de valores. Eficiente quando k é pequeno em relação a n; não adequado para grandes intervalos.","pt_PT":"Uma ordenação não comparativa que conta ocorrências de cada valor e reconstrói o array ordenado. O(n+k) onde k é o intervalo de valores. Eficiente quando k é pequeno em relação a n; não adequado para grandes intervalos."}},
  { id: 'dc-technology-0025', deck_id: 'deck-technology', sort_order: 25, front: "BFS — Breadth-First Search", back: "Graph traversal that visits all neighbors of a node before moving deeper. Uses a queue. O(V+E) time. Finds shortest path in unweighted graphs. Also used for level-order tree traversal." , front_translations: {"de":"BFS — Breitensuche","fr":"BFS — Parcours en largeur","tr":"BFS — Genişlik Öncelikli Arama","nl":"BFS — Breedte-eerst zoeken","ru":"BFS — Обход в ширину","zh":"BFS — 广度优先搜索","pt_BR":"BFS — Busca em Largura","pt_PT":"BFS — Pesquisa em Largura"}, back_translations: {"de":"Graph-Traversierung, die alle Nachbarn eines Knotens besucht, bevor sie tiefer geht. Verwendet eine Warteschlange. O(V+E) Zeit. Findet den kürzesten Pfad in ungewichteten Graphen. Auch für Level-Order-Baumtraversierung verwendet.","fr":"Traversée de graphe qui visite tous les voisins d'un nœud avant d'aller plus en profondeur. Utilise une file d'attente. Temps O(V+E). Trouve le chemin le plus court dans les graphes non pondérés. Aussi utilisé pour la traversée d'arbre en ordre de niveau.","tr":"Daha derine inmeden önce bir düğümün tüm komşularını ziyaret eden graf gezmesi. Kuyruk kullanır. O(V+E) zaman. Ağırlıksız graflarda en kısa yolu bulur. Seviye sırası ağaç gezmesi için de kullanılır.","nl":"Graaftraversaal dat alle buren van een knoop bezoekt voordat het dieper gaat. Gebruikt een wachtrij. O(V+E) tijd. Vindt kortste pad in ongewogen grafen. Ook gebruikt voor niveauvolgorde boomtraversaal.","ru":"Обход графа, посещающий всех соседей узла прежде чем двигаться глубже. Использует очередь. Время O(V+E). Находит кратчайший путь в невзвешенных графах. Также используется для обхода дерева по уровням.","zh":"在深入之前访问节点所有邻居的图遍历算法。使用队列。时间O(V+E)。在无权图中找最短路径。也用于树的层次遍历。","pt_BR":"Travessia de grafo que visita todos os vizinhos de um nó antes de ir mais fundo. Usa uma fila. Tempo O(V+E). Encontra o caminho mais curto em grafos não ponderados. Também usado para travessia em nível de árvore.","pt_PT":"Travessia de grafo que visita todos os vizinhos de um nó antes de ir mais fundo. Usa uma fila. Tempo O(V+E). Encontra o caminho mais curto em grafos não ponderados. Também usado para travessia por nível de árvore."}},
  { id: 'dc-technology-0026', deck_id: 'deck-technology', sort_order: 26, front: "DFS — Depth-First Search", back: "Graph traversal that explores as far as possible along each branch before backtracking. Uses a stack (or recursion). O(V+E) time. Used for topological sort, cycle detection, and maze solving." },
  { id: 'dc-technology-0027', deck_id: 'deck-technology', sort_order: 27, front: "Dijkstra's Algorithm", back: "Finds the shortest path from a source to all vertices in a weighted graph with non-negative edges. Uses a priority queue. O((V+E) log V) with a binary heap. Not suitable for negative edge weights." },
  { id: 'dc-technology-0028', deck_id: 'deck-technology', sort_order: 28, front: "Dynamic Programming (DP)", back: "A technique solving complex problems by breaking them into overlapping subproblems, solving each once and storing results (memoization or tabulation). Key: optimal substructure + overlapping subproblems. E.g., Fibonacci, knapsack." },
  { id: 'dc-technology-0029', deck_id: 'deck-technology', sort_order: 29, front: "Greedy Algorithm", back: "Makes the locally optimal choice at each step hoping to find the global optimum. Simple and efficient but not always correct. Works for: activity selection, Huffman coding, Dijkstra's. Does not work for: 0/1 knapsack." },
  { id: 'dc-technology-0030', deck_id: 'deck-technology', sort_order: 30, front: "Divide and Conquer", back: "An algorithm design paradigm: divide the problem into smaller subproblems, solve recursively, and combine results. Examples: merge sort, quicksort, binary search, Strassen's matrix multiplication." },
  { id: 'dc-technology-0031', deck_id: 'deck-technology', sort_order: 31, front: "Recursion", back: "A function that calls itself with a smaller input until a base case is reached. Elegant for tree/graph problems, but can cause stack overflow if too deep. Often converted to iteration with explicit stack for efficiency." },
  { id: 'dc-technology-0032', deck_id: 'deck-technology', sort_order: 32, front: "Memoization", back: "An optimization technique for recursion where results of expensive function calls are stored (cached) so they don't need to be recomputed. Top-down approach to dynamic programming." },
  { id: 'dc-technology-0033', deck_id: 'deck-technology', sort_order: 33, front: "Encapsulation (OOP)", back: "The bundling of data (attributes) and the methods that operate on that data within a class, hiding internal implementation details and exposing only what is necessary through a public interface." },
  { id: 'dc-technology-0034', deck_id: 'deck-technology', sort_order: 34, front: "Inheritance (OOP)", back: "A mechanism where a subclass acquires the properties and behaviors of a parent class. Promotes code reuse. Types: single, multiple (C++, Python), multilevel. Violating Liskov Substitution Principle is a common pitfall." },
  { id: 'dc-technology-0035', deck_id: 'deck-technology', sort_order: 35, front: "Polymorphism (OOP)", back: "The ability of different objects to respond to the same interface in different ways. Compile-time polymorphism: method overloading. Runtime polymorphism: method overriding via virtual functions or interfaces." },
  { id: 'dc-technology-0036', deck_id: 'deck-technology', sort_order: 36, front: "Abstraction (OOP)", back: "Hiding complex implementation details and showing only the essential features. Achieved through abstract classes and interfaces. Reduces complexity and allows focus on what an object does rather than how." },
  { id: 'dc-technology-0037', deck_id: 'deck-technology', sort_order: 37, front: "Interface vs. Abstract Class", back: "Interface: a contract with no implementation (in most languages); a class can implement multiple interfaces. Abstract class: can have partial implementation; typically single inheritance. Interfaces favor composition over inheritance." },
  { id: 'dc-technology-0038', deck_id: 'deck-technology', sort_order: 38, front: "SOLID Principles", back: "Five OOP design principles: Single Responsibility, Open/Closed, Liskov Substitution, Interface Segregation, Dependency Inversion. Guide toward maintainable, extensible, and testable code." },
  { id: 'dc-technology-0039', deck_id: 'deck-technology', sort_order: 39, front: "Design Pattern: Singleton", back: "A creational pattern ensuring only one instance of a class exists and providing a global access point. Useful for shared resources (database connection, logger). Criticized for making testing difficult (global state)." },
  { id: 'dc-technology-0040', deck_id: 'deck-technology', sort_order: 40, front: "Design Pattern: Factory Method", back: "A creational pattern defining an interface for creating objects but letting subclasses decide which class to instantiate. Decouples object creation from usage and makes code more extensible." },
  { id: 'dc-technology-0041', deck_id: 'deck-technology', sort_order: 41, front: "Design Pattern: Observer", back: "A behavioral pattern where an object (subject) maintains a list of dependents (observers) and notifies them of state changes. Forms the basis of event-driven programming and reactive frameworks." },
  { id: 'dc-technology-0042', deck_id: 'deck-technology', sort_order: 42, front: "Design Pattern: MVC", back: "Model-View-Controller: separates an application into Model (data/business logic), View (user interface), and Controller (handles input, updates model). Promotes separation of concerns and testability." },
  { id: 'dc-technology-0043', deck_id: 'deck-technology', sort_order: 43, front: "Design Pattern: Strategy", back: "A behavioral pattern that defines a family of algorithms, encapsulates each one, and makes them interchangeable. The client can select the algorithm at runtime. Replaces complex if-else or switch statements." },
  { id: 'dc-technology-0044', deck_id: 'deck-technology', sort_order: 44, front: "Design Pattern: Decorator", back: "A structural pattern that adds behavior to objects dynamically by wrapping them in decorator objects implementing the same interface. Favors composition over inheritance. E.g., Java I/O streams." },
  { id: 'dc-technology-0045', deck_id: 'deck-technology', sort_order: 45, front: "TCP/IP", back: "Transmission Control Protocol / Internet Protocol. The foundational suite of communication protocols for the internet. TCP ensures reliable, ordered data delivery; IP handles addressing and routing." },
  { id: 'dc-technology-0046', deck_id: 'deck-technology', sort_order: 46, front: "OSI Model", back: "A 7-layer conceptual framework: Physical, Data Link, Network, Transport, Session, Presentation, Application. Each layer provides services to the layer above and uses services of the layer below." },
  { id: 'dc-technology-0047', deck_id: 'deck-technology', sort_order: 47, front: "OSI Model Layers Mnemonic", back: "All People Seem To Need Data Processing (Application, Presentation, Session, Transport, Network, Data Link, Physical). Or from bottom: Please Do Not Throw Sausage Pizza Away." },
  { id: 'dc-technology-0048', deck_id: 'deck-technology', sort_order: 48, front: "HTTP vs. HTTPS", back: "HTTP: HyperText Transfer Protocol; transfers data in plaintext, port 80. HTTPS: HTTP Secure; encrypts with TLS/SSL, port 443. HTTPS protects data confidentiality, integrity, and authenticates the server." },
  { id: 'dc-technology-0049', deck_id: 'deck-technology', sort_order: 49, front: "DNS — Domain Name System", back: "Translates human-readable domain names (e.g., google.com) into IP addresses. Hierarchical distributed database. DNS resolution: browser cache → OS cache → recursive resolver → root → TLD → authoritative nameserver." },
  { id: 'dc-technology-0050', deck_id: 'deck-technology', sort_order: 50, front: "TLS/SSL", back: "Transport Layer Security / Secure Sockets Layer. A cryptographic protocol providing secure communication over a network. Uses asymmetric encryption for key exchange, then symmetric encryption for data. Certificates verify identity." },
  { id: 'dc-technology-0051', deck_id: 'deck-technology', sort_order: 51, front: "TCP Three-Way Handshake", back: "The process establishing a TCP connection: SYN (client initiates) → SYN-ACK (server acknowledges and responds) → ACK (client acknowledges). After this, data can be transmitted reliably." },
  { id: 'dc-technology-0052', deck_id: 'deck-technology', sort_order: 52, front: "UDP — User Datagram Protocol", back: "A connectionless transport protocol with no guaranteed delivery, ordering, or duplicate protection. Much lower overhead than TCP. Used where speed > reliability: video streaming, DNS, VoIP, gaming." },
  { id: 'dc-technology-0053', deck_id: 'deck-technology', sort_order: 53, front: "IP Address: IPv4 vs. IPv6", back: "IPv4: 32-bit address (e.g., 192.168.1.1), ~4.3 billion addresses. IPv6: 128-bit address (e.g., 2001:0db8::1), ~3.4×10³⁸ addresses; solves IPv4 exhaustion. IPv6 also improves routing and security." },
  { id: 'dc-technology-0054', deck_id: 'deck-technology', sort_order: 54, front: "NAT — Network Address Translation", back: "Maps private IP addresses to a public IP address and vice versa at a router. Allows multiple devices on a LAN to share one public IP. A key response to IPv4 address exhaustion." },
  { id: 'dc-technology-0055', deck_id: 'deck-technology', sort_order: 55, front: "Firewall", back: "A network security device (hardware or software) that monitors and controls incoming/outgoing traffic based on rules. Stateful firewalls track active connections; stateless inspect individual packets." },
  { id: 'dc-technology-0056', deck_id: 'deck-technology', sort_order: 56, front: "REST — Representational State Transfer", back: "An architectural style for web APIs using standard HTTP methods: GET (read), POST (create), PUT/PATCH (update), DELETE (delete). Stateless; resources identified by URLs. Most common web API pattern." },
  { id: 'dc-technology-0057', deck_id: 'deck-technology', sort_order: 57, front: "HTTP Status Codes", back: "2xx: success (200 OK, 201 Created, 204 No Content). 3xx: redirection (301 Moved Permanently, 304 Not Modified). 4xx: client error (400 Bad Request, 401 Unauthorized, 404 Not Found). 5xx: server error (500 Internal Server Error)." },
  { id: 'dc-technology-0058', deck_id: 'deck-technology', sort_order: 58, front: "Cookies and Sessions", back: "Cookies: small data stored in the browser, sent with each request; used for authentication and tracking. Sessions: server-side storage of user state, identified by a session ID in a cookie. Sessions are more secure." },
  { id: 'dc-technology-0059', deck_id: 'deck-technology', sort_order: 59, front: "JWT — JSON Web Token", back: "A compact, self-contained token encoding claims as a JSON object, signed with a secret or public/private key. Used for stateless authentication. Structure: header.payload.signature. Can be verified without a database lookup." },
  { id: 'dc-technology-0060', deck_id: 'deck-technology', sort_order: 60, front: "OAuth 2.0", back: "An authorization framework allowing third-party applications to access resources on behalf of a user without sharing credentials. Uses access tokens. Used by Google, Facebook, GitHub for 'Login with...' features." },
  { id: 'dc-technology-0061', deck_id: 'deck-technology', sort_order: 61, front: "SQL — Structured Query Language", back: "The standard language for relational database management. Core commands: SELECT, INSERT, UPDATE, DELETE, CREATE, DROP, ALTER. Declarative: describes what you want, not how to get it." },
  { id: 'dc-technology-0062', deck_id: 'deck-technology', sort_order: 62, front: "SQL Joins", back: "INNER JOIN: only matching rows in both tables. LEFT JOIN: all from left + matching from right (NULLs for non-matches). RIGHT JOIN: vice versa. FULL OUTER JOIN: all rows from both tables. CROSS JOIN: cartesian product." },
  { id: 'dc-technology-0063', deck_id: 'deck-technology', sort_order: 63, front: "Database Normalization", back: "Organizing a database to reduce redundancy and improve data integrity. 1NF: atomic values, no repeating groups. 2NF: no partial dependencies. 3NF: no transitive dependencies. Higher forms exist but 3NF is the standard." },
  { id: 'dc-technology-0064', deck_id: 'deck-technology', sort_order: 64, front: "ACID Properties", back: "Properties ensuring reliable database transactions: Atomicity (all or nothing), Consistency (valid state to valid state), Isolation (concurrent transactions don't interfere), Durability (committed data persists after failure)." },
  { id: 'dc-technology-0065', deck_id: 'deck-technology', sort_order: 65, front: "Database Index", back: "A data structure (usually a B-tree) that speeds up data retrieval at the cost of extra storage and slower writes. Indexes on frequently queried columns dramatically reduce O(n) scans to O(log n) lookups." },
  { id: 'dc-technology-0066', deck_id: 'deck-technology', sort_order: 66, front: "NoSQL Databases", back: "Non-relational databases designed for flexible schemas, horizontal scaling, and high performance. Types: document (MongoDB), key-value (Redis), column-family (Cassandra), graph (Neo4j). Sacrifice some ACID for scalability." },
  { id: 'dc-technology-0067', deck_id: 'deck-technology', sort_order: 67, front: "CAP Theorem", back: "A distributed system can guarantee at most two of: Consistency (all nodes see the same data), Availability (every request gets a response), Partition Tolerance (works despite network partitions). Networks partition, so tradeoff is C vs. A." },
  { id: 'dc-technology-0068', deck_id: 'deck-technology', sort_order: 68, front: "Process vs. Thread", back: "Process: an independent program in execution with its own memory space. Thread: a lightweight execution unit within a process sharing the same memory. Threads are cheaper to create but require synchronization for shared data." },
  { id: 'dc-technology-0069', deck_id: 'deck-technology', sort_order: 69, front: "Deadlock", back: "A situation where two or more processes are each waiting for the other to release a resource, causing all of them to be stuck indefinitely. Prevented through resource ordering or timeouts." },
  { id: 'dc-technology-0070', deck_id: 'deck-technology', sort_order: 70, front: "Race Condition", back: "A bug where the outcome of a program depends on the relative timing of operations between threads. Prevented with synchronization mechanisms: mutexes, semaphores, atomic operations." },
  { id: 'dc-technology-0071', deck_id: 'deck-technology', sort_order: 71, front: "Mutex (Mutual Exclusion)", back: "A synchronization primitive ensuring only one thread accesses a critical section at a time. The thread that locks the mutex must unlock it. Different from a semaphore (which can be signaled by a different thread)." },
  { id: 'dc-technology-0072', deck_id: 'deck-technology', sort_order: 72, front: "Semaphore", back: "A synchronization primitive using a counter. A binary semaphore acts like a mutex. A counting semaphore controls access to a pool of resources. Can be signaled by a different thread than the one that waited." },
  { id: 'dc-technology-0073', deck_id: 'deck-technology', sort_order: 73, front: "Virtual Memory", back: "An OS abstraction that gives each process the illusion of having its own large private memory space. Physical RAM is supplemented by disk (swap). Uses page tables for address translation; enables memory isolation." },
  { id: 'dc-technology-0074', deck_id: 'deck-technology', sort_order: 74, front: "Page Fault", back: "Occurs when a program accesses a page not currently in physical memory. The OS must load it from disk. Minor page faults: page is in memory but not mapped. Major page faults: page must be retrieved from disk (expensive)." },
  { id: 'dc-technology-0075', deck_id: 'deck-technology', sort_order: 75, front: "Context Switch", back: "The OS process of saving the state of one process/thread and loading another. Allows multitasking. Involves saving registers, program counter, and memory mappings. Has overhead; too many reduce CPU efficiency." },
  { id: 'dc-technology-0076', deck_id: 'deck-technology', sort_order: 76, front: "Garbage Collection", back: "Automatic memory management that reclaims memory no longer referenced by the program. Approaches: reference counting (Swift, Python), mark-and-sweep (JVM, .NET). Eliminates manual memory management bugs but adds overhead." },
  { id: 'dc-technology-0077', deck_id: 'deck-technology', sort_order: 77, front: "Stack vs. Heap (Memory)", back: "Stack: automatically managed LIFO memory for local variables and function calls; fast but limited in size. Heap: dynamically allocated memory; larger but requires manual management (C/C++) or garbage collection; slower allocation." },
  { id: 'dc-technology-0078', deck_id: 'deck-technology', sort_order: 78, front: "Cache (CPU)", back: "A small, fast memory between the CPU and main RAM storing frequently accessed data. L1 (fastest, smallest), L2, L3 (slowest, largest) caches. Cache miss: data must be fetched from slower memory." },
  { id: 'dc-technology-0079', deck_id: 'deck-technology', sort_order: 79, front: "Compiler vs. Interpreter", back: "Compiler: translates entire source code to machine code before execution (e.g., C, Rust). Fast runtime but slow compilation. Interpreter: executes source code line-by-line (e.g., Python). Slower runtime but immediate execution. JIT compilation is a hybrid." },
  { id: 'dc-technology-0080', deck_id: 'deck-technology', sort_order: 80, front: "Version Control: Git", back: "A distributed version control system tracking changes in source code. Key concepts: commit (snapshot), branch (parallel development), merge (combine branches), clone (copy repo), push/pull (sync with remote). Created by Linus Torvalds." },
  { id: 'dc-technology-0081', deck_id: 'deck-technology', sort_order: 81, front: "Git Branching Strategies", back: "Common strategies: GitHub Flow (feature branches → main), Git Flow (develop/feature/release/hotfix branches), trunk-based development (frequent commits to main). Branching enables parallel feature development without conflicts." },
  { id: 'dc-technology-0082', deck_id: 'deck-technology', sort_order: 82, front: "CI/CD — Continuous Integration / Continuous Deployment", back: "CI: automated testing on every code commit to catch bugs early. CD: automated deployment to production after passing tests. Reduces manual errors and enables frequent, reliable software releases." },
  { id: 'dc-technology-0083', deck_id: 'deck-technology', sort_order: 83, front: "Containerization (Docker)", back: "Packages an application and its dependencies into a portable container that runs consistently across environments. Unlike VMs, containers share the host OS kernel, making them lightweight and fast to start." },
  { id: 'dc-technology-0084', deck_id: 'deck-technology', sort_order: 84, front: "Kubernetes (K8s)", back: "An open-source container orchestration platform for automating deployment, scaling, and management of containerized applications. Key concepts: pod (smallest unit), service (networking), deployment (desired state)." },
  { id: 'dc-technology-0085', deck_id: 'deck-technology', sort_order: 85, front: "Microservices Architecture", back: "An architectural style decomposing an application into small, independent services each running its own process and communicating via APIs. Enables independent deployment and scaling but increases operational complexity." },
  { id: 'dc-technology-0086', deck_id: 'deck-technology', sort_order: 86, front: "Monolithic Architecture", back: "A single, self-contained application where all components (UI, business logic, data access) are deployed as one unit. Simpler to develop initially but becomes harder to scale and maintain as it grows." },
  { id: 'dc-technology-0087', deck_id: 'deck-technology', sort_order: 87, front: "API — Application Programming Interface", back: "A set of defined rules allowing software applications to communicate. Defines the methods and data formats clients can use to interact with a service. REST and GraphQL are common web API styles." },
  { id: 'dc-technology-0088', deck_id: 'deck-technology', sort_order: 88, front: "GraphQL", back: "A query language and runtime for APIs where the client specifies exactly what data it needs. Avoids over-fetching and under-fetching. Single endpoint vs. multiple REST endpoints. Developed by Facebook." },
  { id: 'dc-technology-0089', deck_id: 'deck-technology', sort_order: 89, front: "WebSocket", back: "A full-duplex communication protocol over a single TCP connection enabling real-time, bidirectional communication between client and server. Used for chat, live updates, multiplayer games, and financial tickers." },
  { id: 'dc-technology-0090', deck_id: 'deck-technology', sort_order: 90, front: "CDN — Content Delivery Network", back: "A geographically distributed network of servers caching static content (images, scripts, videos) closer to end users. Reduces latency, improves load times, and increases availability. Examples: Cloudflare, AWS CloudFront." },
  { id: 'dc-technology-0091', deck_id: 'deck-technology', sort_order: 91, front: "Load Balancer", back: "A system distributing network traffic across multiple servers to prevent any single server from becoming a bottleneck. Improves availability and scalability. Algorithms: round-robin, least connections, IP hash." },
  { id: 'dc-technology-0092', deck_id: 'deck-technology', sort_order: 92, front: "Caching (General)", back: "Storing the result of expensive operations to serve future requests faster. Hit: data found in cache. Miss: must fetch from source. Cache invalidation (knowing when data is stale) is the hard problem." },
  { id: 'dc-technology-0093', deck_id: 'deck-technology', sort_order: 93, front: "Encryption: Symmetric vs. Asymmetric", back: "Symmetric: same key for encryption and decryption (AES); fast, used for bulk data. Asymmetric: public/private key pair (RSA, ECC); slower, used for key exchange and digital signatures (TLS handshake uses both)." },
  { id: 'dc-technology-0094', deck_id: 'deck-technology', sort_order: 94, front: "Hashing (Security)", back: "A one-way function converting input data into a fixed-size digest (hash). Used to verify data integrity and store passwords. Properties: deterministic, fast to compute, collision-resistant. Examples: SHA-256, bcrypt (for passwords)." },
  { id: 'dc-technology-0095', deck_id: 'deck-technology', sort_order: 95, front: "SQL Injection", back: "A web security vulnerability where user input is included in a SQL query without sanitization, allowing attackers to manipulate the query. Prevented by parameterized queries / prepared statements." },
  { id: 'dc-technology-0096', deck_id: 'deck-technology', sort_order: 96, front: "XSS — Cross-Site Scripting", back: "A web attack injecting malicious scripts into web pages viewed by other users. Reflected XSS: from user input. Stored XSS: persisted in the database. Prevented by escaping output and Content Security Policy (CSP)." },
  { id: 'dc-technology-0097', deck_id: 'deck-technology', sort_order: 97, front: "CSRF — Cross-Site Request Forgery", back: "An attack tricking an authenticated user into unknowingly submitting a malicious request. Prevented by CSRF tokens (unique, unpredictable value validated on the server), SameSite cookie attribute." },
  { id: 'dc-technology-0098', deck_id: 'deck-technology', sort_order: 98, front: "Two's Complement", back: "The standard method for representing signed integers in binary. Negative numbers are the bitwise complement plus 1. This allows the same addition/subtraction circuits to work for both positive and negative numbers." },
  { id: 'dc-technology-0099', deck_id: 'deck-technology', sort_order: 99, front: "Bitwise Operations", back: "Operations directly on binary representations: AND (&), OR (|), XOR (^), NOT (~), left shift (<<), right shift (>>). Used for performance optimization, flags, and low-level hardware programming." },
  { id: 'dc-technology-0100', deck_id: 'deck-technology', sort_order: 100, front: "Floating Point Representation (IEEE 754)", back: "Standard for representing real numbers in binary: sign bit, exponent, and mantissa. 32-bit (float) and 64-bit (double). Precision is limited; 0.1 + 0.2 ≠ 0.3 in floating point arithmetic." },
  { id: 'dc-technology-0101', deck_id: 'deck-technology', sort_order: 101, front: "NP-Completeness", back: "A class of decision problems for which no known polynomial-time algorithm exists. If any NP-complete problem can be solved in polynomial time, all NP problems can (P=NP). Examples: SAT, traveling salesman, graph coloring." },
  { id: 'dc-technology-0102', deck_id: 'deck-technology', sort_order: 102, front: "P vs. NP Problem", back: "One of the Millennium Prize Problems. P: problems solvable in polynomial time. NP: problems whose solutions can be verified in polynomial time. The question is whether P = NP (most believe P ≠ NP)." },
  { id: 'dc-technology-0103', deck_id: 'deck-technology', sort_order: 103, front: "Topological Sort", back: "A linear ordering of vertices in a DAG (directed acyclic graph) such that for every directed edge (u → v), u comes before v. Used for dependency resolution, build systems, and task scheduling. Implemented via DFS or Kahn's algorithm." },
  { id: 'dc-technology-0104', deck_id: 'deck-technology', sort_order: 104, front: "Minimum Spanning Tree (MST)", back: "A subset of edges in a weighted undirected graph that connects all vertices with the minimum total edge weight and no cycles. Algorithms: Kruskal's (greedy, sort edges) and Prim's (greedy, grow from a vertex)." },
  { id: 'dc-technology-0105', deck_id: 'deck-technology', sort_order: 105, front: "Amortized Analysis", back: "Analysis of the average performance of an operation over a sequence of operations, even if individual operations are sometimes expensive. Example: dynamic array doubling is O(1) amortized despite O(n) occasional copies." },
  { id: 'dc-technology-0106', deck_id: 'deck-technology', sort_order: 106, front: "Concurrency vs. Parallelism", back: "Concurrency: multiple tasks make progress by interleaving (e.g., single-core with context switches). Parallelism: multiple tasks execute simultaneously (multi-core). Concurrency is about structure; parallelism is about execution." },
  { id: 'dc-technology-0107', deck_id: 'deck-technology', sort_order: 107, front: "Async/Await and Event Loop", back: "Async functions return Promises in JavaScript; await pauses execution until a Promise resolves without blocking the thread. The event loop processes callbacks when the call stack is empty, enabling non-blocking I/O." },
  { id: 'dc-technology-0108', deck_id: 'deck-technology', sort_order: 108, front: "Functional Programming Concepts", back: "Pure functions (no side effects, deterministic), immutability (data not modified in place), higher-order functions (take/return functions), function composition, map/filter/reduce. Leads to more predictable, testable code." },
  { id: 'dc-technology-0109', deck_id: 'deck-technology', sort_order: 109, front: "Closure", back: "A function that captures (closes over) variables from its enclosing scope, even after that scope has returned. Used for data encapsulation, callbacks, and factory functions. Fundamental to JavaScript and functional programming." },
  { id: 'dc-technology-0110', deck_id: 'deck-technology', sort_order: 110, front: "Dependency Injection (DI)", back: "A design principle where a component's dependencies are provided from outside rather than created internally. Improves testability (inject mocks), decoupling, and flexibility. Core to frameworks like Spring and Angular." },
  { id: 'dc-technology-0111', deck_id: 'deck-technology', sort_order: 111, front: "Test-Driven Development (TDD)", back: "A development practice of writing failing tests before writing production code (Red → Green → Refactor cycle). Ensures code is testable from the start and acts as living documentation." },
  { id: 'dc-technology-0112', deck_id: 'deck-technology', sort_order: 112, front: "Unit Test vs. Integration Test vs. E2E Test", back: "Unit test: tests a single function/class in isolation. Integration test: tests interaction between modules. End-to-end (E2E) test: tests entire user flows through the system. Testing pyramid: many unit, fewer integration, fewest E2E." },
  { id: 'dc-technology-0113', deck_id: 'deck-technology', sort_order: 113, front: "Memory Leak", back: "A bug where memory that is no longer needed is not released back to the OS. In languages without GC (C, C++), caused by failing to free heap memory. In managed languages, caused by retaining unintended references." },
  { id: 'dc-technology-0114', deck_id: 'deck-technology', sort_order: 114, front: "Buffer Overflow", back: "A vulnerability where a program writes more data to a buffer than it can hold, overwriting adjacent memory. Can be exploited to execute arbitrary code. Prevented by bounds checking and safe string functions." },
  { id: 'dc-technology-0115', deck_id: 'deck-technology', sort_order: 115, front: "Binary (Number System)", back: "Base-2 number system using digits 0 and 1. All computer data is ultimately represented in binary. Each binary digit is a bit. A byte is 8 bits, representing 256 possible values (0–255)." },
  { id: 'dc-technology-0116', deck_id: 'deck-technology', sort_order: 116, front: "Hexadecimal (Number System)", back: "Base-16 number system using 0–9 and A–F. Compact representation of binary (1 hex digit = 4 bits). Widely used for memory addresses, color codes (#RRGGBB), and byte-level data representation." },
  { id: 'dc-technology-0117', deck_id: 'deck-technology', sort_order: 117, front: "Boolean Logic: AND / OR / NOT", back: "AND: true only if both inputs are true. OR: true if at least one input is true. NOT: inverts the input. NAND and NOR are functionally complete (any logic circuit can be built from them alone)." },
  { id: 'dc-technology-0118', deck_id: 'deck-technology', sort_order: 118, front: "Regular Expression (Regex)", back: "A sequence of characters defining a search pattern. Used for string matching, validation, and parsing. Special characters: . (any char), * (zero or more), + (one or more), ^ (start), $ (end), [] (character class)." },
  { id: 'dc-technology-0119', deck_id: 'deck-technology', sort_order: 119, front: "Serialization / Deserialization", back: "Serialization: converting an object in memory to a format (JSON, XML, binary) for storage or transmission. Deserialization: reconstructing the object from the format. Key for APIs, persistence, and distributed systems." },
  { id: 'dc-technology-0120', deck_id: 'deck-technology', sort_order: 120, front: "JSON — JavaScript Object Notation", back: "A lightweight, human-readable data interchange format using key-value pairs and arrays. Language-independent but based on JavaScript syntax. The dominant format for REST APIs and configuration files." },
  { id: 'dc-technology-0121', deck_id: 'deck-technology', sort_order: 121, front: "Webhook", back: "A mechanism for one server to notify another via an HTTP POST request when an event occurs ('reverse API'). The receiving server registers a URL (endpoint) and is pushed data rather than polling for updates." },
  { id: 'dc-technology-0122', deck_id: 'deck-technology', sort_order: 122, front: "Message Queue", back: "A system enabling asynchronous communication between services by placing messages in a queue for the receiver to process independently. Examples: RabbitMQ, Apache Kafka, AWS SQS. Decouples producers from consumers." },
  { id: 'dc-technology-0123', deck_id: 'deck-technology', sort_order: 123, front: "Event-Driven Architecture", back: "A design pattern where services communicate by producing and consuming events. Decouples producers from consumers, enabling scalability and loose coupling. Used in serverless, microservices, and real-time systems." },
  { id: 'dc-technology-0124', deck_id: 'deck-technology', sort_order: 124, front: "Idempotency", back: "A property of an operation that produces the same result regardless of how many times it is performed. Crucial in APIs and distributed systems. GET, PUT, DELETE should be idempotent; POST generally is not." },
  { id: 'dc-technology-0125', deck_id: 'deck-technology', sort_order: 125, front: "Latency vs. Throughput", back: "Latency: the time to complete a single operation (ms). Throughput: the number of operations completed per unit time (requests/sec). Optimizing for one can harm the other; balance depends on use case." },
  { id: 'dc-technology-0126', deck_id: 'deck-technology', sort_order: 126, front: "Horizontal vs. Vertical Scaling", back: "Vertical scaling (scale up): add more resources to one machine (CPU, RAM). Horizontal scaling (scale out): add more machines. Horizontal scaling is preferred for cloud-native systems; no single point of failure." },
  { id: 'dc-technology-0127', deck_id: 'deck-technology', sort_order: 127, front: "Eventual Consistency", back: "A consistency model in distributed systems where all replicas will converge to the same value eventually, but may not be consistent at any given moment. Used by many NoSQL databases and DNS." },
  { id: 'dc-technology-0128', deck_id: 'deck-technology', sort_order: 128, front: "Sharding (Database)", back: "Horizontal partitioning of data across multiple database instances (shards) to distribute load and storage. Each shard holds a subset of the data. Increases scalability but complicates queries and transactions." },
  { id: 'dc-technology-0129', deck_id: 'deck-technology', sort_order: 129, front: "Replication (Database)", back: "Maintaining copies of data on multiple servers for redundancy and read scalability. Primary-replica: writes to primary, reads from replicas. Multi-primary allows writes to any node. Trade-off: consistency complexity." },
  { id: 'dc-technology-0130', deck_id: 'deck-technology', sort_order: 130, front: "Machine Learning: Supervised vs. Unsupervised", back: "Supervised learning: model trained on labeled data to predict outputs (classification, regression). Unsupervised learning: model finds patterns in unlabeled data (clustering, dimensionality reduction). Reinforcement learning: learns via rewards." },
  { id: 'dc-technology-0131', deck_id: 'deck-technology', sort_order: 131, front: "Overfitting and Underfitting", back: "Overfitting: model fits training data too closely, failing to generalize to new data. Underfitting: model is too simple to capture the underlying pattern. Balance via regularization, cross-validation, and appropriate model complexity." },
  { id: 'dc-technology-0132', deck_id: 'deck-technology', sort_order: 132, front: "Big Data: 3 Vs", back: "Volume (enormous amounts of data), Velocity (high speed of data generation and processing), Variety (diverse types: structured, semi-structured, unstructured). Sometimes extended to Veracity and Value." },
  { id: 'dc-technology-0133', deck_id: 'deck-technology', sort_order: 133, front: "Blockchain", back: "A distributed, append-only ledger where data is stored in cryptographically linked blocks. Immutable and tamper-resistant without a central authority. Basis of cryptocurrencies; also used in supply chain and smart contracts." },
  { id: 'dc-technology-0134', deck_id: 'deck-technology', sort_order: 134, front: "CORS — Cross-Origin Resource Sharing", back: "A browser mechanism allowing (or blocking) web pages from making requests to a different domain than the one serving the page. Servers must include appropriate CORS headers (Access-Control-Allow-Origin) to allow cross-origin requests." },
  { id: 'dc-technology-0135', deck_id: 'deck-technology', sort_order: 135, front: "Serverless Computing", back: "A cloud execution model where the provider manages the infrastructure and automatically scales function execution. Developers deploy code (functions) without managing servers. Pay-per-use; examples: AWS Lambda, Azure Functions." },
  { id: 'dc-technology-0136', deck_id: 'deck-technology', sort_order: 136, front: "Infrastructure as Code (IaC)", back: "Managing and provisioning infrastructure through machine-readable configuration files rather than manual processes. Tools: Terraform, AWS CloudFormation, Pulumi. Enables version control and reproducible environments." },
  { id: 'dc-technology-0137', deck_id: 'deck-technology', sort_order: 137, front: "Proxy vs. Reverse Proxy", back: "Proxy (forward proxy): client-side; forwards client requests to servers (anonymity, caching). Reverse proxy: server-side; receives client requests and forwards to backend servers (load balancing, SSL termination, caching). Example: Nginx." },
  { id: 'dc-technology-0138', deck_id: 'deck-technology', sort_order: 138, front: "Object vs. Primitive Types", back: "Primitive types (int, float, bool, char) hold values directly and are typically stack-allocated. Objects/reference types hold a reference (pointer) to heap-allocated data. Copying primitives copies values; copying objects copies references." },
  { id: 'dc-technology-0139', deck_id: 'deck-technology', sort_order: 139, front: "Generics (Type Parameters)", back: "A programming feature allowing classes, functions, or interfaces to operate on types specified at instantiation time. Provides type safety without code duplication. E.g., List<T> in Java/C#, templates in C++." },
  { id: 'dc-technology-0140', deck_id: 'deck-technology', sort_order: 140, front: "Monads (Functional Programming)", back: "A design pattern for handling computations with context (e.g., nullable values, async operations, errors) in a chainable, composable way. Examples: Option/Maybe (null safety), Result/Either (error handling), Promise/Future (async)." },
  { id: 'dc-technology-0141', deck_id: 'deck-technology', sort_order: 141, front: "Event Sourcing", back: "A persistence pattern where state is derived from a sequence of immutable events rather than storing the current state. Enables full audit trails, temporal queries, and easy event replay for rebuilding state." },
  { id: 'dc-technology-0142', deck_id: 'deck-technology', sort_order: 142, front: "CQRS — Command Query Responsibility Segregation", back: "An architectural pattern separating read (query) and write (command) operations into different models. Optimizes each independently; pairs well with event sourcing and microservices. Increases complexity." },
  { id: 'dc-technology-0143', deck_id: 'deck-technology', sort_order: 143, front: "Rate Limiting", back: "Controlling the number of requests a client can make to an API within a time window. Prevents abuse, DDoS attacks, and resource exhaustion. Implemented with token bucket or leaky bucket algorithms." },
  { id: 'dc-technology-0144', deck_id: 'deck-technology', sort_order: 144, front: "SSH — Secure Shell", back: "A cryptographic network protocol for secure remote login, command execution, and file transfer. Replaces insecure Telnet and FTP. Uses public-key authentication or passwords; all traffic is encrypted. Default port 22." },
  { id: 'dc-technology-0145', deck_id: 'deck-technology', sort_order: 145, front: "Monorepo vs. Polyrepo", back: "Monorepo: all projects in a single repository (easy sharing, atomic commits, complex tooling). Polyrepo: each project in its own repository (simpler per-project, harder cross-project coordination). Used by Google (monorepo) and Amazon (polyrepo)." },
  { id: 'dc-technology-0146', deck_id: 'deck-technology', sort_order: 146, front: "Code Review", back: "A systematic examination of code by peers before merging. Improves code quality, knowledge sharing, and catches bugs early. Pull/merge requests are the typical mechanism. Review focuses on logic, readability, and standards." },
  { id: 'dc-technology-0147', deck_id: 'deck-technology', sort_order: 147, front: "Technical Debt", back: "The implied cost of rework caused by choosing an easy, short-term solution over a better but more complex approach. Accumulates over time; must be managed through refactoring. The 'interest' on technical debt grows with time." },
  { id: 'dc-technology-0148', deck_id: 'deck-technology', sort_order: 148, front: "Agile Development", back: "An iterative software development methodology emphasizing collaboration, customer feedback, and small, frequent releases. Key practices: sprints (Scrum), user stories, retrospectives, continuous integration." },
  { id: 'dc-technology-0149', deck_id: 'deck-technology', sort_order: 149, front: "DevOps", back: "A cultural and technical practice combining development and operations teams to shorten the system development lifecycle. Emphasizes automation, monitoring, CI/CD, and infrastructure as code." },
  { id: 'dc-technology-0150', deck_id: 'deck-technology', sort_order: 150, front: "Moore's Law", back: "The observation by Gordon Moore (1965) that the number of transistors on a microchip doubles approximately every two years, driving exponential growth in computing power while costs decline. Slowing since ~2015." },
];
